import { getMockReq } from "@jest-mock/express"
import { DefaultedArgs } from "../../../../src/node/cli"
import { maybeProxy } from "../../../../src/node/routes/domainProxy"

describe("domain proxy", () => {
  const proxyDomain = "domain.ltd"

  const proxyPortFor = (host: string): string | undefined => {
    const req = getMockReq({ headers: { host } })
    req.args = { "proxy-domain": [proxyDomain] } as DefaultedArgs
    return maybeProxy(req)
  }

  it("proxies a port in its own subdomain", () => {
    expect(proxyPortFor("5140.domain.ltd")).toBe("5140")
  })

  it("proxies a port followed by a hyphenated suffix in one subdomain", () => {
    expect(proxyPortFor("5140-code.domain.ltd")).toBe("5140")
  })

  it("does not proxy a non-port subdomain", () => {
    expect(proxyPortFor("code.domain.ltd")).toBeUndefined()
  })

  it("does not proxy multiple subdomains", () => {
    expect(proxyPortFor("5140.test.domain.ltd")).toBeUndefined()
  })
})
